var { createTerminal } = require("./terminal");

var MAX_TERMINALS = 10;
var SCROLLBACK_MAX = 50 * 1024; // 50 KB per terminal

/**
 * Create a terminal manager for a project.
 * Manages persistent PTY sessions with scrollback buffering.
 * opts: { cwd, send, sendTo }
 */
function createTerminalManager(opts) {
  var cwd = opts.cwd;
  var send = opts.send;
  var sendTo = opts.sendTo;

  var nextId = 1;
  var terminals = new Map(); // id -> terminal session

  function create(cols, rows) {
    if (terminals.size > MAX_TERMINALS) return null;

    var id = nextId++;
    var term = createTerminal({
      cols: cols,
      rows: rows,
      cwd: cwd,
      onData: function (data) {
        send({ type: "terminal-data", id: id, data: data });
      },
      onExit: function () {
        terminals.delete(id);
        send({ type: "terminal-exit", id: id });
      },
    });
    terminals.set(id, {
      term: term,
      scrollback: "",
      scrollbackSize: 0,
    });
    return id;
  }

  function write(id, data) {
    var t = terminals.get(id);
    if (!t) return false;
    t.term.write(data);
    // Append to scrollback buffer
    t.scrollback += data;
    t.scrollbackSize += data.length;
    // Trim scrollback if too large
    if (t.scrollbackSize > SCROLLBACK_MAX) {
      var excess = t.scrollbackSize - SCROLLBACK_MAX;
      t.scrollback = t.scrollback.slice(excess);
      t.scrollbackSize = SCROLLBACK_MAX;
    }
    return true;
  }

  function resize(id, cols, rows) {
    var t = terminals.get(id);
    if (!t) return false;
    t.term.resize(cols, rows);
    return true;
  }

  function getScrollback(id) {
    var t = terminals.get(id);
    if (!t) return null;
    return t.scrollback;
  }

  return {
    create,
    write,
    resize,
    getScrollback,
  };
}

module.exports = {
  createTerminalManager,
};
